Map<String, String> decodeForm(String body) {
  final result = <String, String>{};
  if (body.isEmpty) {
    return result;
  }
  for (final field in body.split('&')) {
    final equals = field.indexOf('=');
    if (equals < 0) {
      throw FormatException('form field is missing =');
    }
    final key = Uri.decodeComponent(field.substring(0, equals));
    final value = Uri.decodeComponent(field.substring(equals + 1));
    result[key] = value;
  }
  return result;
}

