import '../lib/form_decoder.dart';
import '../lib/form_encoder.dart';
import '../lib/query_fields.dart';

void expectEqual(Object? actual, Object? expected) {
  if (actual != expected) {
    throw StateError('Expected $expected, got $actual');
  }
}

void main() {
  final encoded = encodeForm(<String, String>{'city': 'Oslo', 'page': '2'});
  expectEqual(encoded, 'city=Oslo&page=2');
  expectEqual(decodeForm(encoded).toString(), '{city: Oslo, page: 2}');
  expectEqual(isSupportedFieldName('account_id'), true);
  expectEqual(isSupportedFieldName('9account'), false);
}
